private enum BumbleScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("découvr") || t.contains("swipe") || t.contains("flame") || t.contains("match") || t.contains("timeline") || t.contains("map") || t.contains("top"):
            BumbleSwipeScreen()
        case let t where t.contains("chat") || t.contains("message"):
            BumbleMatchesScreen()
        case let t where t.contains("profil") || t.contains("profile"):
            BumbleDatingProfileScreen()
        default:
            BumbleGenericListScreen(title: tab)
        }
    }
}
